import re
from app.schemas.models import DetectedEntity

# ══════════════════════════════════════════════════════════════ < 정규표현식 개인정보 탐지 > ══════════════════════════════════════════════════════════════

# < 공통 기능 > ──────────────────────────────────────────
# (1) 두 span이 겹치는지 is_overlapping으로 확인
def is_overlapping(span1, span2):
    s1, e1 = span1
    s2, e2 = span2
    return not (e1 <= s2 or e2 <= s1)

# (2) 새로운 span이 기존 탐지된 span 목록과 겹치는 지 확인 (하나라도 겹치면 안 됨)
def _no_overlap(span, matched_spans):
    return not any(is_overlapping(span, s) for s in matched_spans)


# < 위험도 매핑 > ──────────────────────────────────────────
RISK_MAP = {
    "주민등록번호": "high", 
    "외국인등록번호": "high",
    "카드번호": "high", 
    "계좌번호": "high", 
    "여권번호": "high",
    "전화번호": "medium", 
    "이메일": "medium", 
    "차량번호": "medium",
    "사업자등록번호": "medium", 
    "법인등록번호": "medium",
    "IPv4": "low", 
    "IPv6": "low", 
    "현금영수증": "low",
}

def _get_risk(entity_type: str) -> str:
    for key, level in RISK_MAP.items():
        if key in entity_type:
            return level
    return "medium"

# < 정규표현식 탐지 > ──────────────────────────────────────────
# 1. 전화번호

_PHONE = re.compile(
    r'(?<!\d)'
    r'(?:'
        r'(?:0(?:2|3[1-3]|4[1-4]|5[1-5]|6[1-4]|70|80))'
        r'[-\s]?\d{3,4}[-\s]?\d{4}'
        r'|'
        r'01[01]'
        r'[-\s]?\d{3,4}[-\s]?\d{4}'
    r')'
    r'(?!\d)'
)
_PHONE_KEYWORDS = r'전화번호|전화|휴대폰|핸드폰|연락처|번호|TEL|tel|phone|mobile|연락|전번'
_PHONE_KEYWORD = re.compile(
    r'(?:' + _PHONE_KEYWORDS + r')[\s:：\-]*'
    r'(01[01][-\s]?\d{3,4}[-\s]?\d{4}'
    r'|0\d{1,2}[-\s]?\d{3,4}[-\s]?\d{4})',
    re.IGNORECASE
)

def detect_phone(text: str) -> list:
    results = []
    matched_spans = []

    for m in _PHONE_KEYWORD.finditer(text):
        span = m.span()
        if _no_overlap(span, matched_spans):
            results.append({"type": "전화번호(키워드)", "value": m.group(), "span": span})
            matched_spans.append(span)

    for m in _PHONE.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "전화번호", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    return results

# ──────────────────────────────────────────
# 2. 사업자등록번호

_BUSINESS_REG = re.compile(
    r'(?<!\d)'
    r'([1-9]\d{2})'
    r'-?'
    r'(0[1-9]|[1-7]\d|8[125678]|9[0-9])'
    r'-?'
    r'(\d{4}[1-9]|[1-9]\d{4})'
    r'(?!\d)'
)

_BUSINESS_REG_KW = re.compile(
    r'(?:사업자등록번호|사업자번호|사업자|등록번호|거래처|세금계산서|'
    r'법인번호|과세번호|면세번호|BRN)[\s:：\-]*'
    r'([1-9]\d{2})-?(0[1-9]|[1-7]\d|8[125678]|9[0-9])-?(\d{4}[1-9]|[1-9]\d{4})',
    re.IGNORECASE
)

def detect_business_reg(text: str) -> list:
    results = []
    matched_spans = []

    for m in _BUSINESS_REG_KW.finditer(text):
        span = m.span()
        if _no_overlap(span, matched_spans):
            results.append({"type": "사업자등록번호", "value": m.group(), "span": span})
            matched_spans.append(span)

    for m in _BUSINESS_REG.finditer(text):
        span = m.span()
        if _no_overlap(span, matched_spans):
            results.append({"type": "사업자등록번호", "value": m.group(), "span": span})
            matched_spans.append(span)

    return results


