_CORP_NUM_PAT = (
    r'(\d{4})'
    r'(11|12|13|14|20|21|22|31|32|33|34|35|40|41|50|60|70|71)'
    r'-?'
    r'(\d{7})'
)
_CORP_REG = re.compile(r'(?<!\d)' + _CORP_NUM_PAT + r'\b')
_CORP_KEYWORDS = (
    r'법인등록번호|법인번호|법인등록|등록번호|법인정보|법인|'
    r'등기번호|등기|주식회사|유한회사|유한책임회사|사단법인|재단법인|'
    r'사회적협동조합|협동조합|비영리법인|영리법인'
)
_CORP_KEYWORD_PATTERN = re.compile(r'(?:' + _CORP_KEYWORDS + r')[\s:：\-]*', re.IGNORECASE)

def detect_corp_reg(text: str) -> list:
    results = []
    matched_spans = []

    for kw_match in _CORP_KEYWORD_PATTERN.finditer(text):
        after_kw = kw_match.end()
        remaining = text[after_kw:]
        m = _CORP_REG.match(remaining)
        if m:
            real_span = (after_kw + m.start(), after_kw + m.end())
            if _no_overlap(real_span, matched_spans):
                results.append({"type": "법인등록번호", "value": m.group(), "span": real_span})
                matched_spans.append(real_span)

    for m in _CORP_REG.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "법인등록번호", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    results.sort(key=lambda x: x["span"][0])
    return results


# ──────────────────────────────────────────
# 7. 이메일

_EMAIL = re.compile(
    r'\b[A-Za-z0-9._%+\-가-힣]+@[A-Za-z0-9.가-힣\-]+\.[A-Za-z가-힣]{2,}\b',
    re.IGNORECASE
)

def detect_email(text: str) -> list:
    return [
        {"type": "이메일", "value": m.group(), "span": m.span()}
        for m in _EMAIL.finditer(text)
    ]


