# 8. IP 주소 (IPv4 / IPv6)

_OCTET = r'(?:25[0-5]|2[0-4]\d|[01]?\d\d?)'
_IPV4_BODY = rf'{_OCTET}\.{_OCTET}\.{_OCTET}\.{_OCTET}'
_IPv4 = re.compile(rf'(?<![:\w]){_IPV4_BODY}(?![:\w])')
_IP_KEYWORDS = r'IP주소|IP|아이피주소|아이피|ip주소|ip|서버주소|서버|접속주소|호스트'
_IPv4_KEYWORD = re.compile(
    rf'(?:{_IP_KEYWORDS})[\s:：\-]*'
    rf'({_OCTET})[\s.]({_OCTET})[\s.]({_OCTET})[\s.]({_OCTET})(?!\d)',
    re.IGNORECASE
)
_IPv6 = re.compile(
    rf'(?<![:\w])'
    rf'(?:'
        rf'(?:[0-9A-Fa-f]{{1,4}}:){{6}}{_IPV4_BODY}'
        rf'|::(?:[0-9A-Fa-f]{{1,4}}:)?{_IPV4_BODY}'
        rf'|(?:[0-9A-Fa-f]{{1,4}}:){{1,5}}:{_IPV4_BODY}'
        rf'|(?:[0-9A-Fa-f]{{1,4}}:){{7}}[0-9A-Fa-f]{{1,4}}'
        rf'|(?:[0-9A-Fa-f]{{1,4}}:){{1,7}}:'
        rf'|(?:[0-9A-Fa-f]{{1,4}}:){{1,6}}:[0-9A-Fa-f]{{1,4}}'
        rf'|(?:[0-9A-Fa-f]{{1,4}}:){{1,5}}(?::[0-9A-Fa-f]{{1,4}}){{1,2}}'
        rf'|(?:[0-9A-Fa-f]{{1,4}}:){{1,4}}(?::[0-9A-Fa-f]{{1,4}}){{1,3}}'
        rf'|(?:[0-9A-Fa-f]{{1,4}}:){{1,3}}(?::[0-9A-Fa-f]{{1,4}}){{1,4}}'
        rf'|(?:[0-9A-Fa-f]{{1,4}}:){{1,2}}(?::[0-9A-Fa-f]{{1,4}}){{1,5}}'
        rf'|[0-9A-Fa-f]{{1,4}}:(?::[0-9A-Fa-f]{{1,4}}){{1,6}}'
        rf'|:(?::[0-9A-Fa-f]{{1,4}}){{1,7}}'
        rf'|::'
    rf')'
    rf'(?:%[0-9A-Za-z_.-]+)?'
    rf'(?![:\w])',
    re.IGNORECASE
)

def detect_ip(text: str) -> list:
    results = []
    matched_spans = []

    for m in _IPv6.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "IPv6", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    for m in _IPv4_KEYWORD.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "IPv4(키워드)", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    for m in _IPv4.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "IPv4", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    results.sort(key=lambda x: x["span"][0])
    return results


