# 10. 주민등록번호 / 외국인등록번호 / 법인등록번호 통합 구분 탐지

# 주민등록번호
_RRN = re.compile(
    r'(?<!\d)(\d{2}(?:0[1-9]|1[0-2])(?:0[1-9]|[12]\d|3[01]))'
    r'[-\s]?([1-4]\d{6})(?!\d)'
)
# 외국인등록번호
_FRN = re.compile(
    r'(?<!\d)(\d{2}(?:0[1-9]|1[0-2])(?:0[1-9]|[12]\d|3[01]))'
    r'[-\s]?([5-8]\d{6})(?!\d)'
)
_RRN_KEYWORDS = r'주민등록번호|주민번호|주민등록|주민|생년월일|생년|뒷자리'
_FRN_KEYWORDS = r'외국인등록번호|외국인번호|외국인등록|체류카드|외국인'
_RRN_KEYWORD = re.compile(
    r'(?:' + _RRN_KEYWORDS + r')[은는이가의도요를]?[\s:：\-]*'
    r'(\d{2}(?:0[1-9]|1[0-2])(?:0[1-9]|[12]\d|3[01]))'
    r'[-\s]?([1-4]\d{6})',
    re.IGNORECASE
)
_FRN_KEYWORD = re.compile(
    r'(?:' + _FRN_KEYWORDS + r')[은는이가의도요를]?[\s:：\-]*'
    r'(\d{2}(?:0[1-9]|1[0-2])(?:0[1-9]|[12]\d|3[01]))'
    r'[-\s]?([5-8]\d{6})',
    re.IGNORECASE
)
_CORP_KEYWORD2 = re.compile(
    r'(?:' + _CORP_KEYWORDS + r')[은는이가의도요를]?[\s:：\-]*' + _CORP_NUM_PAT,
    re.IGNORECASE
)

def detect_rrn_frn(text: str) -> list:
    results = []
    matched_spans = []

    for m in _RRN_KEYWORD.finditer(text):
        span = m.span()
        if _no_overlap(span, matched_spans):
            results.append({"type": "주민등록번호(키워드)", "value": m.group(), "span": span})
            matched_spans.append(span)

    for m in _FRN_KEYWORD.finditer(text):
        span = m.span()
        if _no_overlap(span, matched_spans):
            results.append({"type": "외국인등록번호(키워드)", "value": m.group(), "span": span})
            matched_spans.append(span)

    for m in _CORP_KEYWORD2.finditer(text):
        span = m.span()
        if _no_overlap(span, matched_spans):
            results.append({"type": "법인등록번호(키워드)", "value": m.group(), "span": span})
            matched_spans.append(span)

    for m in _RRN.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "주민등록번호", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    for m in _FRN.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "외국인등록번호", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    for m in _CORP_REG.finditer(text):
        if _no_overlap(m.span(), matched_spans):
            results.append({"type": "법인등록번호", "value": m.group(), "span": m.span()})
            matched_spans.append(m.span())

    results.sort(key=lambda x: x["span"][0])
    return results


